import{_ as a,o as r,c as e,ae as o}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"《诗经·关雎》鉴赏","description":"","frontmatter":{},"headers":[],"relativePath":"jing/关雎.md","filePath":"jing/关雎.md"}'),n={name:"jing/关雎.md"};function h(d,t,i,s,l,p){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="《诗经·关雎》鉴赏" tabindex="-1">《诗经·关雎》鉴赏 <a class="header-anchor" href="#《诗经·关雎》鉴赏" aria-label="Permalink to &quot;《诗经·关雎》鉴赏&quot;">​</a></h1><hr><h2 id="原文" tabindex="-1">原文 <a class="header-anchor" href="#原文" aria-label="Permalink to &quot;原文&quot;">​</a></h2><blockquote><p>关关雎鸠，在河之洲。 窈窕淑女，君子好逑。</p><p>参差荇菜，左右流之。 窈窕淑女，寤寐求之。</p><p>求之不得，寤寐思服。 悠哉悠哉，辗转反侧。</p><p>参差荇菜，左右采之。 窈窕淑女，琴瑟友之。</p><p>参差荇菜，左右芼之。 窈窕淑女，钟鼓乐之。</p></blockquote><hr><h2 id="题解" tabindex="-1">题解 <a class="header-anchor" href="#题解" aria-label="Permalink to &quot;题解&quot;">​</a></h2><p>《关雎》是《诗经》的开篇之作，也是《风》之始。</p><p><strong>雎鸠</strong> — 水鸟名，相传这种鸟配偶固定，生死不离，故古人以之象征忠贞的爱情。</p><p><strong>窈窕</strong> — 形容女子娴静美好的姿态。</p><p><strong>荇菜</strong> — 一种水生植物，嫩叶可食。此处指淑女劳作之景。</p><hr><h2 id="艺术手法" tabindex="-1">艺术手法 <a class="header-anchor" href="#艺术手法" aria-label="Permalink to &quot;艺术手法&quot;">​</a></h2><h3 id="_1-起兴" tabindex="-1">1. 起兴 <a class="header-anchor" href="#_1-起兴" aria-label="Permalink to &quot;1. 起兴&quot;">​</a></h3><p>以雎鸠鸟的相依相伴起兴，引出君子对淑女的追求，以物喻情，奠定全诗基调。</p><h3 id="_2-叙事层次" tabindex="-1">2. 叙事层次 <a class="header-anchor" href="#_2-叙事层次" aria-label="Permalink to &quot;2. 叙事层次&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>内容</th></tr></thead><tbody><tr><td>初见</td><td>关雎和鸣，触动情思</td></tr><tr><td>追求</td><td>参差荇菜，左右流之；寤寐求之，辗转反侧</td></tr><tr><td>相得</td><td>琴瑟友之，钟鼓乐之</td></tr></tbody></table><h3 id="_3-情感递进" tabindex="-1">3. 情感递进 <a class="header-anchor" href="#_3-情感递进" aria-label="Permalink to &quot;3. 情感递进&quot;">​</a></h3><p>从&quot;求之不得&quot;的辗转难眠，到&quot;琴瑟友之&quot;的情感升华，再到&quot;钟鼓乐之&quot;的完满结局，层次分明，情感真挚。</p><hr><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>《关雎》被列于《诗经》之首，历来被视为&quot;风天下而正夫妇&quot;的典范。它以朴素的语言表达了人类对美好爱情的共同追求，是中国文学中爱情题材的源头之一。</p><hr><p><strong>分类：</strong> 经部 <strong>体裁：</strong> 诗词 <strong>时代：</strong> 先秦 <strong>标签：</strong> 诗经、爱情、思无邪</p>',23)])])}const _=a(n,[["render",h]]);export{u as __pageData,_ as default};
